136	// can't #[derive(Debug)] because Debug is not implemented for arrays 64 items long
137	impl fmt::Debug for Bag {
138	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
139	        f.debug_struct("Bag")
140	            .field("deferreds", &&self.deferreds[..self.len])
141	            .finish()
142	    }
143	}
