594	mod tests {
595	    use std::sync::atomic::AtomicUsize;
596	
597	    use super::*;
598	
599	    #[test]
600	    fn check_defer() {
601	        static FLAG: AtomicUsize = AtomicUsize::new(0);
602	        fn set() {
603	            FLAG.store(42, Ordering::Relaxed);
604	        }
605	
606	        let d = Deferred::new(set);
607	        assert_eq!(FLAG.load(Ordering::Relaxed), 0);
608	        d.call();
609	        assert_eq!(FLAG.load(Ordering::Relaxed), 42);
610	    }
611	
612	    #[test]
613	    fn check_bag() {
614	        static FLAG: AtomicUsize = AtomicUsize::new(0);
615	        fn incr() {
616	            FLAG.fetch_add(1, Ordering::Relaxed);
617	        }
618	
619	        let mut bag = Bag::new();
620	        assert!(bag.is_empty());
621	
622	        for _ in 0..MAX_OBJECTS {
623	            assert!(unsafe { bag.try_push(Deferred::new(incr)).is_ok() });
624	            assert!(!bag.is_empty());
625	            assert_eq!(FLAG.load(Ordering::Relaxed), 0);
626	        }
627	
628	        let result = unsafe { bag.try_push(Deferred::new(incr)) };
