1	/// Epoch-based garbage collector.
2	///
3	/// # Examples
4	///
5	/// ```
6	/// use crossbeam_epoch::Collector;
7	///
8	/// let collector = Collector::new();
9	///
10	/// let handle = collector.register();
11	/// drop(collector); // `handle` still works after dropping `collector`
12	///
13	/// handle.pin().flush();
14	/// ```
15	use core::fmt;
16	
17	use crate::{
18	    guard::Guard,
19	    internal::{Global, Local},
20	    primitive::sync::Arc,
21	};
22	
23	/// An epoch-based garbage collector.
24	pub struct Collector {
25	    pub(crate) global: Arc<Global>,
26	}
27	
28	unsafe impl Send for Collector {}
29	unsafe impl Sync for Collector {}
