41	    /// Creates a new collector.
42	    pub fn new() -> Self {
43	        Self::default()
44	    }
45	
46	    /// Registers a new handle for the collector.
47	    pub fn register(&self) -> LocalHandle {
48	        Local::register(self)
49	    }
50	}
51	
52	impl Clone for Collector {
53	    /// Creates another reference to the same garbage collector.
54	    fn clone(&self) -> Self {
55	        Self {
56	            global: self.global.clone(),
57	        }
58	    }
59	}
