75	/// A handle to a garbage collector.
76	pub struct LocalHandle {
77	    pub(crate) local: *const Local,
78	}
79	
80	impl LocalHandle {
81	    /// Pins the handle.
82	    #[inline]
83	    pub fn pin(&self) -> Guard {
84	        unsafe { (*self.local).pin() }
85	    }
86	
87	    /// Returns `true` if the handle is pinned.
88	    #[inline]
89	    pub fn is_pinned(&self) -> bool {
90	        unsafe { (*self.local).is_pinned() }
91	    }
92	
93	    /// Returns the `Collector` associated with this handle.
94	    #[inline]
95	    pub fn collector(&self) -> &Collector {
96	        unsafe { (*self.local).collector() }
97	    }
98	}
