100	impl Drop for LocalHandle {
101	    #[inline]
102	    fn drop(&mut self) {
103	        unsafe {
104	            Local::release_handle(&*self.local);
105	        }
106	    }
107	}
108	
109	impl fmt::Debug for LocalHandle {
110	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
111	        f.pad("LocalHandle { .. }")
112	    }
113	}
