115	#[cfg(all(test, not(crossbeam_loom)))]
116	#[allow(
117	    clippy::alloc_instead_of_core,
118	    clippy::std_instead_of_alloc,
119	    clippy::std_instead_of_core
120	)]
121	mod tests {
122	    use std::{
123	        mem::ManuallyDrop,
124	        sync::atomic::{AtomicUsize, Ordering},
125	        vec::Vec,
126	    };
