128	    use crossbeam_utils::thread;
129	
130	    use crate::{Collector, Owned};
131	
132	    const NUM_THREADS: usize = 8;
133	
134	    #[test]
135	    fn pin_reentrant() {
136	        let collector = Collector::new();
137	        let handle = collector.register();
138	        drop(collector);
139	
140	        assert!(!handle.is_pinned());
141	        {
142	            let _guard = &handle.pin();
143	            assert!(handle.is_pinned());
144	            {
145	                let _guard = &handle.pin();
146	                assert!(handle.is_pinned());
147	            }
148	            assert!(handle.is_pinned());
149	        }
150	        assert!(!handle.is_pinned());
151	    }
