153	    #[test]
154	    fn flush_local_bag() {
155	        let collector = Collector::new();
156	        let handle = collector.register();
157	        drop(collector);
158	
159	        for _ in 0..100 {
160	            let guard = &handle.pin();
161	            unsafe {
162	                let a = Owned::new(7).into_shared(guard);
163	                guard.defer_destroy(a);
164	
165	                assert!(!(*guard.local).bag.with(|b| (*b).is_empty()));
166	
167	                while !(*guard.local).bag.with(|b| (*b).is_empty()) {
168	                    guard.flush();
169	                }
170	            }
171	        }
172	    }
