174	    #[test]
175	    fn garbage_buffering() {
176	        let collector = Collector::new();
177	        let handle = collector.register();
178	        drop(collector);
179	
180	        let guard = &handle.pin();
181	        unsafe {
182	            for _ in 0..10 {
183	                let a = Owned::new(7).into_shared(guard);
184	                guard.defer_destroy(a);
185	            }
186	            assert!(!(*guard.local).bag.with(|b| (*b).is_empty()));
187	        }
188	    }
