190	    #[test]
191	    fn pin_holds_advance() {
192	        const N: usize = if cfg!(miri) { 500 } else { 500_000 };
193	
194	        let collector = Collector::new();
195	
196	        thread::scope(|scope| {
197	            for _ in 0..NUM_THREADS {
198	                scope.spawn(|_| {
199	                    let handle = collector.register();
200	                    for _ in 0..N {
201	                        let guard = &handle.pin();
202	
203	                        let before = collector.global.epoch.load(Ordering::Relaxed);
204	                        collector.global.collect(guard);
205	                        let after = collector.global.epoch.load(Ordering::Relaxed);
206	
207	                        assert!(after.wrapping_sub(before) <= 2);
208	                    }
209	                });
210	            }
211	        })
