1	//! Michael-Scott lock-free queue.
2	//!
3	//! Usable with any number of producers and consumers.
4	//!
5	//! Michael and Scott.  Simple, Fast, and Practical Non-Blocking and Blocking Concurrent Queue
6	//! Algorithms.  PODC 1996.  <http://dl.acm.org/citation.cfm?id=248106>
7	//!
8	//! Simon Doherty, Lindsay Groves, Victor Luchangco, and Mark Moir. 2004b. Formal Verification of a
9	//! Practical Lock-Free Queue Algorithm. <https://doi.org/10.1007/978-3-540-30232-2_7>
10	
11	use core::{
12	    mem::MaybeUninit,
13	    sync::atomic::Ordering::{Acquire, Relaxed, Release},
14	};
15	
16	use crossbeam_utils::CachePadded;
17	
18	use crate::{Atomic, Guard, Owned, Shared, unprotected};
19	
20	// The representation here is a singly-linked list, with a sentinel node at the front. In general
21	// the `tail` pointer may lag behind the actual tail. Non-sentinel nodes are either all `Data` or
22	// all `Blocked` (requests for data from blocked threads).
23	#[derive(Debug)]
24	pub(crate) struct Queue<T> {
25	    head: CachePadded<Atomic<Node<T>>>,
26	    tail: CachePadded<Atomic<Node<T>>>,
27	}
28	
29	struct Node<T> {
30	    /// The slot in which a value of type `T` can be stored.
31	    ///
32	    /// The type of `data` is `MaybeUninit<T>` because a `Node<T>` doesn't always contain a `T`.
33	    /// For example, the sentinel node in a queue never contains a value: its slot is always empty.
34	    /// Other nodes start their life with a push operation and contain a value until it gets popped
35	    /// out. After that such empty nodes get added to the collector for destruction.
36	    data: MaybeUninit<T>,
37	
38	    next: Atomic<Node<T>>,
39	}
40	
41	// Any particular `T` should never be accessed concurrently, so no need for `Sync`.
42	unsafe impl<T: Send> Sync for Queue<T> {}
43	unsafe impl<T: Send> Send for Queue<T> {}
44	
45	impl<T> Queue<T> {
46	    /// Create a new, empty queue.
47	    pub(crate) fn new() -> Self {
48	        let q = Self {
49	            head: CachePadded::new(Atomic::null()),
50	            tail: CachePadded::new(Atomic::null()),
51	        };
52	        let sentinel = Owned::new(Node {
53	            data: MaybeUninit::uninit(),
54	            next: Atomic::null(),
55	        });
56	        unsafe {
57	            let guard = unprotected();
58	            let sentinel = sentinel.into_shared(guard);
59	            q.head.store(sentinel, Relaxed);
60	            q.tail.store(sentinel, Relaxed);
61	            q
62	        }
63	    }
64	
65	    /// Attempts to atomically place `n` into the `next` pointer of `onto`, and returns `true` on
66	    /// success. The queue's `tail` pointer may be updated.
67	    #[inline(always)]
68	    fn push_internal(
69	        &self,
70	        onto: Shared<'_, Node<T>>,
71	        new: Shared<'_, Node<T>>,
72	        guard: &Guard,
73	    ) -> bool {
74	        // is `onto` the actual tail?
75	        let o = unsafe { onto.deref() };
76	        let next = o.next.load(Acquire, guard);
77	        if unsafe { next.as_ref().is_some() } {
78	            // if not, try to "help" by moving the tail pointer forward
79	            let _ = self
80	                .tail
81	                .compare_exchange(onto, next, Release, Relaxed, guard);
82	            false
83	        } else {
84	            // looks like the actual tail; attempt to link in `n`
85	            let result = o
86	                .next
87	                .compare_exchange(Shared::null(), new, Release, Relaxed, guard)
88	                .is_ok();
89	            if result {
90	                // try to move the tail pointer forward
91	                let _ = self
92	                    .tail
93	                    .compare_exchange(onto, new, Release, Relaxed, guard);
94	            }
95	            result
96	        }
97	    }
98	
99	    /// Adds `t` to the back of the queue, possibly waking up threads blocked on `pop`.
100	    pub(crate) fn push(&self, t: T, guard: &Guard) {
101	        let new = Owned::new(Node {
102	            data: MaybeUninit::new(t),
103	            next: Atomic::null(),
104	        });
105	        let new = Owned::into_shared(new, guard);
106	
107	        loop {
108	            // We push onto the tail, so we'll start optimistically by looking there first.
109	            let tail = self.tail.load(Acquire, guard);
110	
111	            // Attempt to push onto the `tail` snapshot; fails if `tail.next` has changed.
112	            if self.push_internal(tail, new, guard) {
113	                break;
114	            }
115	        }
116	    }
117	
118	    /// Attempts to pop a data node. `Ok(None)` if queue is empty; `Err(())` if lost race to pop.
119	    #[inline(always)]
120	    fn pop_internal(&self, guard: &Guard) -> Result<Option<T>, ()> {
121	        let head = self.head.load(Acquire, guard);
122	        let h = unsafe { head.deref() };
123	        let next = h.next.load(Acquire, guard);
124	        match unsafe { next.as_ref() } {
125	            Some(n) => unsafe {
126	                self.head
127	                    .compare_exchange(head, next, Release, Relaxed, guard)
128	                    .map(|_| {
129	                        let tail = self.tail.load(Relaxed, guard);
130	                        // Advance the tail so that we don't retire a pointer to a reachable node.
131	                        if head == tail {
132	                            let _ = self
133	                                .tail
134	                                .compare_exchange(tail, next, Release, Relaxed, guard);
135	                        }
136	                        guard.defer_destroy(head);
137	                        Some(n.data.assume_init_read())
138	                    })
139	                    .map_err(|_| ())
140	            },
141	            None => Ok(None),
142	        }
143	    }
144	
145	    /// Attempts to pop a data node, if the data satisfies the given condition. `Ok(None)` if queue
146	    /// is empty or the data does not satisfy the condition; `Err(())` if lost race to pop.
147	    #[inline(always)]
148	    fn pop_if_internal<F>(&self, condition: F, guard: &Guard) -> Result<Option<T>, ()>
149	    where
150	        T: Sync,
151	        F: Fn(&T) -> bool,
152	    {
153	        let head = self.head.load(Acquire, guard);
154	        let h = unsafe { head.deref() };
155	        let next = h.next.load(Acquire, guard);
156	        match unsafe { next.as_ref() } {
157	            Some(n) if condition(unsafe { &*n.data.as_ptr() }) => unsafe {
158	                self.head
159	                    .compare_exchange(head, next, Release, Relaxed, guard)
160	                    .map(|_| {
161	                        let tail = self.tail.load(Relaxed, guard);
162	                        // Advance the tail so that we don't retire a pointer to a reachable node.
163	                        if head == tail {
164	                            let _ = self
165	                                .tail
166	                                .compare_exchange(tail, next, Release, Relaxed, guard);
167	                        }
168	                        guard.defer_destroy(head);
169	                        Some(n.data.assume_init_read())
170	                    })
171	                    .map_err(|_| ())
172	            },
173	            None | Some(_) => Ok(None),
174	        }
175	    }
176	
177	    /// Attempts to dequeue from the front.
178	    ///
179	    /// Returns `None` if the queue is observed to be empty.
180	    pub(crate) fn try_pop(&self, guard: &Guard) -> Option<T> {
181	        loop {
182	            if let Ok(head) = self.pop_internal(guard) {
183	                return head;
184	            }
185	        }
186	    }
187	
188	    /// Attempts to dequeue from the front, if the item satisfies the given condition.
189	    ///
190	    /// Returns `None` if the queue is observed to be empty, or the head does not satisfy the given
191	    /// condition.
192	    pub(crate) fn try_pop_if<F>(&self, condition: F, guard: &Guard) -> Option<T>
193	    where
194	        T: Sync,
195	        F: Fn(&T) -> bool,
196	    {
197	        loop {
198	            if let Ok(head) = self.pop_if_internal(&condition, guard) {
199	                return head;
200	            }
201	        }
202	    }
203	}
204	
205	impl<T> Drop for Queue<T> {
206	    fn drop(&mut self) {
207	        unsafe {
208	            let guard = unprotected();
209	
210	            while self.try_pop(guard).is_some() {}
211	
212	            // Destroy the remaining sentinel node.
213	            let sentinel = self.head.load(Relaxed, guard);
214	            drop(sentinel.into_owned());
215	        }
216	    }
217	}
